def _fetch_referral_source_for_settings(source_id: str) -> dict | None:
    source_id = (source_id or '').strip()
    if not source_id:
        return None
    conn = get_conn()
    try:
        with conn.cursor() as cur:
            ensure_referral_sources_table(cur)
            cur.execute(
                """
                SELECT id::text, COALESCE(name,''), COALESCE(company_name,''), COALESCE(source_type,'other'),
                       COALESCE(phone,''), COALESCE(email,''), COALESCE(notes,''), COALESCE(is_active, TRUE)
                FROM referral_sources
                WHERE id = %s::uuid
                LIMIT 1
                """,
                (source_id,),
            )
            row = cur.fetchone()
            if not row:
                return None
            return {
                'source_id': row[0],
                'source_name': row[1],
                'company_name': row[2],
                'source_type': row[3],
                'phone': row[4],
                'email': row[5],
                'notes': row[6],
                'is_active': bool(row[7]),
            }
    finally:
        try:
            conn.close()
        except Exception:
            pass


