def infer_round_number(*values):
    for value in values:
        if value is None:
            continue
        match = re.search(r"round\s*(\d+)", str(value), flags=re.IGNORECASE)
        if match:
            try:
                return int(match.group(1))
            except ValueError:
                pass
    return None


def fetch_saved_letters(cur, client_id: str, limit: int = 100):
    cur.execute("""
        SELECT l.id::text,
               COALESCE(meta.round_number, NULL),
               l.bureau::text,
               COALESCE(l.subject, ''),
               l.generated_at,
               COALESCE(meta.include_accounts, TRUE),
               COALESCE(meta.include_personal_info, FALSE),
               COALESCE(meta.include_inquiries, FALSE),
               COALESCE(meta.letter_instructions, ''),
               COALESCE(l.round_run_id::text, '')
        FROM letters l
        LEFT JOIN round_run_dispute_meta meta ON meta.round_run_id = l.round_run_id
        WHERE l.client_id = %s
        ORDER BY l.generated_at DESC
        LIMIT %s
    """, (client_id, limit))
    rows = cur.fetchall()
    out = []
    for r in rows:
        round_number = r[1] or infer_round_number(r[3])
        categories = []
        if r[5]:
            categories.append('Accounts')
        if r[6]:
            categories.append('Personal Info')
        if r[7]:
            categories.append('Inquiries')
        category_label = ' + '.join(categories) if categories else 'Accounts'
        bureau_label = (r[2] or '').title()
        if round_number:
            title = f"Dispute Letter - Round {round_number} - {bureau_label} - {category_label}"
        else:
            title = r[3] or f"Dispute Letter - {bureau_label} - {category_label}"

        raw_subject = r[3] or ''
        generic_subject = (not raw_subject.strip()
            or bool(re.fullmatch(r"\s*Dispute Letter\s*-\s*Round\s*\d+\s*", raw_subject, flags=re.IGNORECASE))
            or bool(re.fullmatch(r"\s*Round\s*\d+\s*dispute\s*letter\s*", raw_subject, flags=re.IGNORECASE)))
        display_subject = title if generic_subject else raw_subject

        out.append({
            'id': r[0], 'round_number': round_number, 'bureau': r[2], 'subject': display_subject,
            'raw_subject': raw_subject, 'generated_at': str(r[4]) if r[4] else '', 'include_accounts': bool(r[5]),
            'include_personal_info': bool(r[6]), 'include_inquiries': bool(r[7]),
            'letter_instructions': r[8], 'round_run_id': r[9], 'title': title,
        })
    return out

def fetch_saved_letter_detail(cur, client_id: str, letter_id: str):
    cur.execute("""
        SELECT l.id::text,
               COALESCE(meta.round_number, NULL),
               COALESCE(l.bureau::text, ''),
               COALESCE(l.subject, ''),
               COALESCE(l.letter_text, ''),
               l.generated_at,
               COALESCE(l.use_client_signature, FALSE),
               COALESCE(l.round_run_id::text, '')
        FROM letters l
        LEFT JOIN round_run_dispute_meta meta ON meta.round_run_id = l.round_run_id
        WHERE l.client_id = %s
          AND l.id = %s
        LIMIT 1
    """, (client_id, letter_id))
    row = cur.fetchone()
    if not row:
        return None
    return {
        'id': row[0],
        'round_number': int(row[1] or 0) if row[1] is not None else None,
        'bureau': row[2],
        'subject': row[3],
        'letter_text': row[4],
        'generated_at': str(row[5]) if row[5] else '',
        'use_client_signature': bool(row[6]),
        'round_run_id': row[7],
    }


def fetch_bureau_letter_history(cur, client_id: str, bureau: str, before_round: Optional[int] = None, limit: int = 12):
    params = [client_id, (bureau or '').strip().lower()]
    round_filter = ""
    if before_round and int(before_round) > 0:
        round_filter = " AND COALESCE(meta.round_number, 0) < %s"
        params.append(int(before_round))
    params.append(int(limit))
    cur.execute(f"""
        SELECT l.id::text,
               COALESCE(meta.round_number, NULL),
               COALESCE(l.bureau::text, ''),
               COALESCE(l.subject, ''),
               COALESCE(l.letter_text, ''),
               l.generated_at,
               COALESCE(l.round_run_id::text, '')
        FROM letters l
        LEFT JOIN round_run_dispute_meta meta ON meta.round_run_id = l.round_run_id
        WHERE l.client_id = %s
          AND lower(COALESCE(l.bureau::text, '')) = %s
          {round_filter}
        ORDER BY COALESCE(meta.round_number, 0) DESC, l.generated_at DESC
        LIMIT %s
    """, tuple(params))
    rows = cur.fetchall()
    return [{
        'id': r[0],
        'round_number': int(r[1] or 0) if r[1] is not None else None,
        'bureau': r[2],
        'subject': r[3],
        'letter_text': r[4],
        'generated_at': str(r[5]) if r[5] else '',
        'round_run_id': r[6],
    } for r in rows]


def fetch_latest_bureau_letter(cur, client_id: str, bureau: str, before_round: Optional[int] = None):
    rows = fetch_bureau_letter_history(cur, client_id, bureau, before_round=before_round, limit=1)
    return rows[0] if rows else None



def _safe_template_filename(value: str) -> str:
    stem = re.sub(r'[^A-Za-z0-9._ -]+', '', (value or '').strip())
    stem = stem.strip().strip('.')
    return stem


def _template_stage_from_name(name: str) -> int:
    m = re.search(r'(?:stage|round)\s*[_ -]?(\d+)', (name or ''), flags=re.IGNORECASE)
    return int(m.group(1)) if m else 0


def _template_bureau_dir(bureau: str) -> Path:
    clean = (bureau or '').strip().lower()
    if clean not in CUSTOM_LETTER_TEMPLATE_BUREAUS:
        clean = 'equifax'
    path = Path(CUSTOM_LETTER_TEMPLATE_DIR) / clean
    path.mkdir(parents=True, exist_ok=True)
    return path


def _template_id_from_path(path: Path, bureau: str) -> str:
    return f"{bureau}:{path.name}"


def _resolve_custom_template_path(template_id: str) -> tuple[str, Optional[Path]]:
    raw = str(template_id or '').strip()
    if not raw:
        return '', None
    if ':' in raw:
        bureau, fname = raw.split(':', 1)
    else:
        bureau, fname = '', raw
    bureau = (bureau or '').strip().lower()
    fname = _safe_template_filename(fname)
    if bureau not in CUSTOM_LETTER_TEMPLATE_BUREAUS or not fname:
        return '', None
    path = _template_bureau_dir(bureau) / fname
    return bureau, path if path.exists() else None


def _extract_docx_template_text(path: Path) -> str:
    try:
        with zipfile.ZipFile(path, 'r') as zf:
            xml_bytes = zf.read('word/document.xml')
        root = ET.fromstring(xml_bytes)
        ns = {'w': 'http://schemas.openxmlformats.org/wordprocessingml/2006/main'}
        paragraphs = []
        for para in root.findall('.//w:p', ns):
            texts = []
            for node in para.findall('.//w:t', ns):
                texts.append(node.text or '')
            joined = ''.join(texts).strip()
            if joined:
                paragraphs.append(joined)
        return '\n\n'.join(paragraphs).strip()
    except Exception:
        return ''


def list_custom_letter_templates():
    templates_out = []
    base = Path(CUSTOM_LETTER_TEMPLATE_DIR)
    if not base.exists():
        return templates_out
    for bureau in CUSTOM_LETTER_TEMPLATE_BUREAUS:
        bureau_dir = base / bureau
        if not bureau_dir.exists():
            continue
        for path in sorted(bureau_dir.glob('*.docx')):
            name = path.stem
            templates_out.append({
                'id': _template_id_from_path(path, bureau),
                'name': name,
                'bureau': bureau,
                'stage': _template_stage_from_name(name),
                'file_name': path.name,
                'path': str(path),
                'content': '',
                'kind': 'docx',
            })
    templates_out.sort(key=lambda x: ((x.get('bureau') or ''), int(x.get('stage') or 0), (x.get('name') or '').lower()))
    return templates_out


def load_custom_letter_template(template_id: str):
    bureau, path = _resolve_custom_template_path(template_id)
    if not path:
        return None
    name = path.stem
    return {
        'id': _template_id_from_path(path, bureau),
        'name': name,
        'bureau': bureau,
        'stage': _template_stage_from_name(name),
        'file_name': path.name,
        'path': str(path),
        'content': _extract_docx_template_text(path),
        'kind': 'docx',
    }


def save_custom_letter_template_upload(upload: UploadFile, bureau: str):
    if upload is None or not getattr(upload, 'filename', ''):
        raise ValueError('Choose a Word .docx template to upload.')
    bureau = (bureau or '').strip().lower()
    if bureau not in CUSTOM_LETTER_TEMPLATE_BUREAUS:
        raise ValueError('Choose a valid bureau template folder.')
    original = upload.filename
    if not original.lower().endswith('.docx'):
        raise ValueError('Only Word .docx template files are supported.')
    safe_name = _safe_template_filename(original)
    if not safe_name.lower().endswith('.docx'):
        safe_name += '.docx'
    path = _template_bureau_dir(bureau) / safe_name
    content = upload.file.read()
    if not content:
        raise ValueError('The uploaded template file is empty.')
    path.write_bytes(content)
    return load_custom_letter_template(_template_id_from_path(path, bureau))


def delete_custom_letter_template(template_id: str):
    bureau, path = _resolve_custom_template_path(template_id)
    if not path:
        return False
    try:
        path.unlink(missing_ok=True)
        return True
    except Exception:
        return False

def _round_override_table_exists(cur) -> bool:
    try:
        cur.execute("SELECT to_regclass('public.client_bureau_round_overrides')::text")
        row = cur.fetchone()
        return bool(row and row[0])
    except Exception:
        return False


def fetch_bureau_round_override(cur, client_id: str, bureau: str) -> Optional[int]:
    if not _round_override_table_exists(cur):
        return None
    cur.execute("""
        SELECT current_round_number
        FROM client_bureau_round_overrides
        WHERE client_id = %s
          AND lower(bureau) = %s
        LIMIT 1
    """, (client_id, (bureau or '').strip().lower()))
    row = cur.fetchone()
    if not row or row[0] is None:
        return None
    try:
        return max(int(row[0]), 1)
    except Exception:
        return None


def fetch_all_bureau_round_overrides(cur, client_id: str) -> dict:
    if not _round_override_table_exists(cur):
        return {}
    cur.execute("""
        SELECT lower(bureau), current_round_number
        FROM client_bureau_round_overrides
        WHERE client_id = %s
    """, (client_id,))
    out = {}
    for bureau, num in cur.fetchall():
        try:
            out[(bureau or '').strip().lower()] = max(int(num), 1)
        except Exception:
            continue
    return out


def upsert_bureau_round_override(cur, client_id: str, bureau: str, current_round_number: int):
    if not _round_override_table_exists(cur):
        raise RuntimeError("Round override table is missing. Run the supplied SQL script first.")
    cur.execute("""
        INSERT INTO client_bureau_round_overrides (client_id, bureau, current_round_number, updated_at)
        VALUES (%s, %s, %s, CURRENT_TIMESTAMP)
        ON CONFLICT (client_id, bureau) DO UPDATE
        SET current_round_number = EXCLUDED.current_round_number,
            updated_at = CURRENT_TIMESTAMP
    """, (client_id, (bureau or '').strip().lower(), max(int(current_round_number or 1), 1)))


def clear_bureau_round_override(cur, client_id: str, bureau: str):
    if not _round_override_table_exists(cur):
        return
    cur.execute("DELETE FROM client_bureau_round_overrides WHERE client_id = %s AND lower(bureau) = %s", (client_id, (bureau or '').strip().lower()))




def fetch_client_emails(cur, client_id: str, limit: int = 200):
    cur.execute("""
        SELECT id::text,
               COALESCE(direction, 'outbound'),
               COALESCE(subject, ''),
               COALESCE(body_text, ''),
               COALESCE(from_email, ''),
               COALESCE(to_email, ''),
               COALESCE(cc_email, ''),
               email_date,
               related_round,
               COALESCE(email_type, 'general'),
               COALESCE(status, 'logged'),
               COALESCE(source, 'manual'),
               created_at
        FROM client_emails
        WHERE client_id = %s
        ORDER BY COALESCE(email_date, created_at) DESC, created_at DESC
        LIMIT %s
    """, (client_id, limit))
    rows = cur.fetchall()
    return [{
        'id': r[0], 'direction': r[1], 'subject': r[2], 'body_text': r[3],
        'from_email': r[4], 'to_email': r[5], 'cc_email': r[6],
        'email_date': str(r[7]) if r[7] else '', 'related_round': r[8],
        'email_type': r[9], 'status': r[10], 'source': r[11],
        'created_at': str(r[12]) if r[12] else ''
    } for r in rows]




def fetch_latest_sent_round_for_bureau(cur, client_id: str, bureau: str) -> int:
    bureau = (bureau or '').strip().lower()
    cur.execute("""
        SELECT COALESCE(MAX(COALESCE(meta.round_number, 0)), 0)
        FROM letters l
        LEFT JOIN round_run_dispute_meta meta ON meta.round_run_id = l.round_run_id
        WHERE l.client_id = %s
          AND lower(COALESCE(l.bureau::text, '')) = %s
    """, (client_id, bureau))
    row = cur.fetchone()
    return int(row[0] or 0) if row else 0


def fetch_dispute_round_defaults(cur, client_id: str):
    cur.execute("""
        SELECT COALESCE(MAX(COALESCE(meta.round_number, 0)), 0)
        FROM letters l
        LEFT JOIN round_run_dispute_meta meta ON meta.round_run_id = l.round_run_id
        WHERE l.client_id = %s
    """, (client_id,))
    row = cur.fetchone()
    round_number = (int(row[0] or 0) + 1) if row else 1
    if round_number < 1:
        round_number = 1

    cur.execute("""
        SELECT COALESCE(m.letter_instructions, '')
        FROM round_run_dispute_meta m
        JOIN letters l ON l.round_run_id = m.round_run_id
        WHERE l.client_id = %s
        ORDER BY COALESCE(l.generated_at, m.created_at) DESC, m.created_at DESC
        LIMIT 1
    """, (client_id,))
    row = cur.fetchone()
    return {
        'current_round_number': round_number,
        'last_letter_instructions': row[0] if row and row[0] else ''
    }


def get_current_round_number(cur, client_id: str) -> int:
    return int(fetch_dispute_round_defaults(cur, client_id).get('current_round_number', 1) or 1)


def fetch_dispute_metrics(cur, client_id: str):
    metrics = {}
    cur.execute("""
        SELECT
            COUNT(*) FILTER (WHERE COALESCE(round_added, 1) = 1) AS started_count,
            COUNT(*) FILTER (WHERE COALESCE(is_active, TRUE) = TRUE) AS current_count,
            COUNT(*) FILTER (WHERE COALESCE(is_active, TRUE) = FALSE) AS removed_count,
            COUNT(*) FILTER (WHERE COALESCE(round_added, 1) > 1 AND COALESCE(is_active, TRUE) = TRUE) AS new_count
        FROM client_account_disputes
        WHERE client_id = %s
    """, (client_id,))
    row = cur.fetchone() or (0, 0, 0, 0)
    metrics['accounts'] = {'started': int(row[0] or 0), 'current': int(row[1] or 0), 'removed': int(row[2] or 0), 'new': int(row[3] or 0)}

    cur.execute("""
        SELECT
            COUNT(*) FILTER (WHERE COALESCE(round_added, 1) = 1) AS started_count,
            COUNT(*) FILTER (WHERE COALESCE(is_active, TRUE) = TRUE) AS current_count,
            COUNT(*) FILTER (WHERE COALESCE(is_active, TRUE) = FALSE) AS removed_count,
            COUNT(*) FILTER (WHERE COALESCE(round_added, 1) > 1 AND COALESCE(is_active, TRUE) = TRUE) AS new_count
        FROM client_personal_info_disputes
        WHERE client_id = %s
    """, (client_id,))
    row = cur.fetchone() or (0, 0, 0, 0)
    metrics['personal_info'] = {'started': int(row[0] or 0), 'current': int(row[1] or 0), 'removed': int(row[2] or 0), 'new': int(row[3] or 0)}

    cur.execute("""
        SELECT
            COUNT(*) FILTER (WHERE COALESCE(round_added, 1) = 1) AS started_count,
            COUNT(*) FILTER (WHERE COALESCE(is_active, TRUE) = TRUE) AS current_count,
            COUNT(*) FILTER (WHERE COALESCE(is_active, TRUE) = FALSE) AS removed_count,
            COUNT(*) FILTER (WHERE COALESCE(round_added, 1) > 1 AND COALESCE(is_active, TRUE) = TRUE) AS new_count
        FROM client_inquiry_disputes
        WHERE client_id = %s
    """, (client_id,))
    row = cur.fetchone() or (0, 0, 0, 0)
    metrics['inquiries'] = {'started': int(row[0] or 0), 'current': int(row[1] or 0), 'removed': int(row[2] or 0), 'new': int(row[3] or 0)}
    return metrics




def _safe_parse_date(value):
    if not value:
        return None
    if isinstance(value, datetime):
        return value.date()
    if isinstance(value, date):
        return value
    text = str(value).strip()
    if not text:
        return None
    for parser in (
        lambda t: datetime.fromisoformat(t.replace('Z', '+00:00')).date(),
        lambda t: datetime.strptime(t[:10], '%Y-%m-%d').date(),
        lambda t: datetime.strptime(t[:10], '%m/%d/%Y').date(),
    ):
        try:
            return parser(text)
        except Exception:
            continue
    return None


def get_current_round_number_for_bureau(cur, client_id: str, bureau: str) -> int:
    override_round = fetch_bureau_round_override(cur, client_id, bureau)
    if override_round and override_round >= 1:
        return override_round
    latest_sent_round = fetch_latest_sent_round_for_bureau(cur, client_id, bureau)
    return latest_sent_round + 1 if latest_sent_round >= 1 else 1


def build_bureau_dispute_summaries(profile: dict, account_disputes: list, personal_info_disputes: list,
                                   inquiry_disputes: list, saved_letters: list, redispute_events: list,
                                   current_round_default: int, round_overrides: Optional[dict] = None) -> dict:
    summaries = {}
    account_disputes = account_disputes or []
    personal_info_disputes = personal_info_disputes or []
    inquiry_disputes = inquiry_disputes or []
    saved_letters = saved_letters or []
    redispute_events = redispute_events or []
    round_overrides = round_overrides or {}
    today = date.today()
    full_name = ' '.join([p for p in [profile.get('first_name'), profile.get('middle_name'), profile.get('last_name')] if p]).strip()
    for bureau in BUREAUS:
        items = []
        for source, kind in ((account_disputes, 'accounts'), (personal_info_disputes, 'personal_info'), (inquiry_disputes, 'inquiries')):
            for item in source:
                if (item.get('bureau') or '').strip().lower() == bureau:
                    copy = dict(item)
                    copy['_kind'] = kind
                    items.append(copy)

        started_negative = sum(1 for item in items if int(item.get('round_added') or 1) <= 1)
        current_active = sum(1 for item in items if bool(item.get('is_active')))
        removed = sum(1 for item in items if not bool(item.get('is_active')))
        new_since_started = sum(1 for item in items if int(item.get('round_added') or 1) > 1)

        letters = [l for l in saved_letters if (l.get('bureau') or '').strip().lower() == bureau]
        letters.sort(key=lambda x: ((_safe_parse_date(x.get('generated_at')) or date.min), int(x.get('round_number') or 0)), reverse=True)
        latest_letter = letters[0] if letters else None
        latest_round_sent = int(latest_letter.get('round_number') or 0) if latest_letter else 0
        latest_date = _safe_parse_date(latest_letter.get('generated_at')) if latest_letter else None
        override_round = round_overrides.get(bureau)
        current_round = override_round if override_round and int(override_round) >= 1 else (latest_round_sent + 1 if latest_round_sent else 1)

        next_tickler_event = None
        future_events = []
        for event in redispute_events:
            if (event.get('bureau') or '').strip().lower() != bureau:
                continue
            event_date = _safe_parse_date(event.get('event_date'))
            if event_date and event_date >= today:
                future_events.append((event_date, event))
        future_events.sort(key=lambda t: t[0])
        if future_events:
            next_tickler_event = future_events[0][1]

        summaries[bureau] = {
            'bureau': bureau,
            'full_name': full_name,
            'started_negative': started_negative,
            'current_active': current_active,
            'removed': removed,
            'new_since_started': new_since_started,
            'latest_round_sent': latest_round_sent,
            'date_sent': format_short_date(latest_date) if latest_date else '',
            'next_round_tickler': format_short_date(next_tickler_event.get('event_date')) if next_tickler_event else '',
            'current_round': current_round,
        }
    return summaries


def build_bureau_dispute_round_summary(cur, client_id: str, bureau: str, round_number: int, include_personal_info: bool, include_inquiries: bool):
    bureau = (bureau or '').strip().lower()
    cur.execute("""
        SELECT COUNT(*) FILTER (WHERE COALESCE(round_added,1) <= 1),
               COUNT(*) FILTER (WHERE COALESCE(is_active, TRUE) = TRUE),
               COUNT(*) FILTER (WHERE COALESCE(is_active, TRUE) = FALSE),
               COUNT(*) FILTER (WHERE COALESCE(round_added,1) > 1)
        FROM client_account_disputes
        WHERE client_id = %s AND lower(COALESCE(bureau, '')) = %s
    """, (client_id, bureau))
    acct = cur.fetchone() or (0, 0, 0, 0)
    parts = [
        f"{bureau.title()} dispute letter generated for round {round_number}.",
        f"Accounts: started {int(acct[0] or 0)}, current {int(acct[1] or 0)}, removed {int(acct[2] or 0)}, new since we started {int(acct[3] or 0)}."
    ]
    if include_personal_info:
        cur.execute("""
            SELECT COUNT(*) FILTER (WHERE COALESCE(round_added,1) <= 1),
                   COUNT(*) FILTER (WHERE COALESCE(is_active, TRUE) = TRUE),
                   COUNT(*) FILTER (WHERE COALESCE(is_active, TRUE) = FALSE),
                   COUNT(*) FILTER (WHERE COALESCE(round_added,1) > 1)
            FROM client_personal_info_disputes
            WHERE client_id = %s AND lower(COALESCE(bureau, '')) = %s
        """, (client_id, bureau))
        row = cur.fetchone() or (0, 0, 0, 0)
        parts.append(f"Personal info: started {int(row[0] or 0)}, current {int(row[1] or 0)}, removed {int(row[2] or 0)}, new since we started {int(row[3] or 0)}.")
    if include_inquiries:
        cur.execute("""
            SELECT COUNT(*) FILTER (WHERE COALESCE(round_added,1) <= 1),
                   COUNT(*) FILTER (WHERE COALESCE(is_active, TRUE) = TRUE),
                   COUNT(*) FILTER (WHERE COALESCE(is_active, TRUE) = FALSE),
                   COUNT(*) FILTER (WHERE COALESCE(round_added,1) > 1)
            FROM client_inquiry_disputes
            WHERE client_id = %s AND lower(COALESCE(bureau, '')) = %s
        """, (client_id, bureau))
        row = cur.fetchone() or (0, 0, 0, 0)
        parts.append(f"Inquiries: started {int(row[0] or 0)}, current {int(row[1] or 0)}, removed {int(row[2] or 0)}, new since we started {int(row[3] or 0)}.")
    return ' '.join(parts)


def ensure_bureau_redispute_tickler(cur, client_id: str, bureau: str, round_number: int, client_name: str, due_date: date):
    bureau = (bureau or '').strip().lower()
    title = f"{bureau.title()} Redispute - {client_name}".strip()
    cur.execute("""
        SELECT id::text FROM client_redispute_events
        WHERE client_id = %s AND lower(COALESCE(bureau, '')) = %s AND round_number = %s AND event_date = %s::date
        LIMIT 1
    """, (client_id, bureau, round_number, due_date))
    if not cur.fetchone():
        cur.execute("""
            INSERT INTO client_redispute_events (client_id, bureau, event_date, round_number, status, notes)
            VALUES (%s, %s, %s::date, %s, 'scheduled', %s)
        """, (client_id, bureau, due_date, round_number, title))

    cur.execute("""
        SELECT id::text FROM client_followups
        WHERE client_id = %s AND followup_type = 'redispute' AND due_date = %s::date AND COALESCE(note_text,'') = %s
        LIMIT 1
    """, (client_id, due_date, title))
    if not cur.fetchone():
        cur.execute("""
            INSERT INTO client_followups (client_id, followup_type, due_date, status, note_text)
            VALUES (%s, 'redispute', %s::date, 'open', %s)
        """, (client_id, due_date, title))

def build_dispute_round_summary(cur, client_id: str, round_number: int, include_personal_info: bool, include_inquiries: bool):
    metrics = fetch_dispute_metrics(cur, client_id)
    parts = [
        f"Round {round_number} processed.",
        f"Accounts: started {metrics['accounts']['started']}, current {metrics['accounts']['current']}, removed {metrics['accounts']['removed']}, new since round 1 {metrics['accounts']['new']}."
    ]
    if include_personal_info:
        parts.append(
            f"Personal info: started {metrics['personal_info']['started']}, current {metrics['personal_info']['current']}, removed {metrics['personal_info']['removed']}, new since round 1 {metrics['personal_info']['new']}."
        )
    if include_inquiries:
        parts.append(
            f"Inquiries tracked: started {metrics['inquiries']['started']}, current {metrics['inquiries']['current']}, removed {metrics['inquiries']['removed']}, new since round 1 {metrics['inquiries']['new']}."
        )
        parts.append("Note: inquiry disputes are tracked in the Credit Repair system in this build, but the legacy generator does not yet merge them into the generated letters.")
    return ' '.join(parts)


